# Unit Tests for `deep_get` Function

```python
import pytest


def deep_get(d: dict, keys: str, default=None):
    """Get nested dict value by dot-separated keys."""
    for key in keys.split('.'):
        if isinstance(d, dict):
            d = d.get(key, default)
        else:
            return default
    return d


class TestDeepGetHappyPath:
    """Test cases for successful retrieval scenarios."""

    def test_single_level_key(self):
        """Test retrieving a value from a single-level dictionary."""
        data = {"name": "John"}
        assert deep_get(data, "name") == "John"

    def test_nested_two_levels(self):
        """Test retrieving a value from a two-level nested dictionary."""
        data = {"user": {"name": "John"}}
        assert deep_get(data, "user.name") == "John"

    def test_nested_three_levels(self):
        """Test retrieving a value from a three-level nested dictionary."""
        data = {"user": {"profile": {"name": "John"}}}
        assert deep_get(data, "user.profile.name") == "John"

    def test_deeply_nested_multiple_levels(self):
        """Test retrieving a value from a deeply nested dictionary."""
        data = {"a": {"b": {"c": {"d": {"e": "value"}}}}}
        assert deep_get(data, "a.b.c.d.e") == "value"

    def test_retrieve_dict_value(self):
        """Test retrieving a dictionary as a value."""
        data = {"user": {"profile": {"name": "John"}}}
        result = deep_get(data, "user.profile")
        assert result == {"name": "John"}

    def test_retrieve_list_value(self):
        """Test retrieving a list as a value."""
        data = {"items": [1, 2, 3]}
        assert deep_get(data, "items") == [1, 2, 3]

    def test_retrieve_none_value(self):
        """Test retrieving None as a stored value."""
        data = {"value": None}
        assert deep_get(data, "value") is None

    def test_retrieve_zero_value(self):
        """Test retrieving zero as a value."""
        data = {"count": 0}
        assert deep_get(data, "count") == 0

    def test_retrieve_false_value(self):
        """Test retrieving False as a value."""
        data = {"active": False}
        assert deep_get(data, "active") is False

    def test_retrieve_empty_string(self):
        """Test retrieving an empty string as a value."""
        data = {"text": ""}
        assert deep_get(data, "text") == ""


